mapper.select:
SELECT bom_id FROM (
    SELECT bom_id
      FROM t_bom_header
     WHERE item_id       = #{itemId}
       AND status        = 'ACTIVE'
       AND is_default    = 'Y'
       AND effective_from <= #{asOf}
       AND (effective_to IS NULL OR effective_to >= #{asOf})
     ORDER BY effective_from DESC
) LIMIT 1

WITH RECURSIVE used_tree AS ( SELECT 1 AS lvl, h.item_id AS parent_item_id, pi.item_code AS parent_code, l.component_item_id, l.qty_per, l.uom, CONCAT('<-', pi.item_code) AS path FROM t_bom_line l JOIN t_bom_header h ON h.bom_id = l.bom_id JOIN t_item pi ON pi.item_id = h.item_id WHERE l.component_item_id = #{componentId} AND h.status = 'ACTIVE' AND h.effective_from <= (SELECT curr_biz_date FROM t_business_date WHERE sys_code = 'CORE') AND (h.effective_to IS NULL OR h.effective_to >= (SELECT curr_biz_date FROM t_business_date WHERE sys_code = 'CORE')) UNION ALL SELECT ut.lvl + 1, h.item_id, pi.item_code, l.component_item_id, l.qty_per, l.uom, CONCAT(ut.path, '<-', pi.item_code) FROM used_tree ut JOIN t_bom_line l ON l.component_item_id = ut.parent_item_id JOIN t_bom_header h ON h.bom_id = l.bom_id JOIN t_item pi ON pi.item_id = h.item_id WHERE h.status = 'ACTIVE' AND h.effective_from <= (SELECT curr_biz_date FROM t_business_date WHERE sys_code = 'CORE') AND (h.effective_to IS NULL OR h.effective_to >= (SELECT curr_biz_date FROM t_business_date WHERE sys_code = 'CORE'))
AND ut.lvl < #{maxLevels}
) SELECT lvl, parent_item_id, component_item_id, qty_per, uom, path FROM used_tree ORDER BY path

SELECT line_id, bom_id, line_no, component_item_id, qty_per, uom, scrap_rate, is_phantom
  FROM t_bom_line
 WHERE bom_id = #{bomId}
